class Story: NSObject, NSSecureCoding {
    
    // MARK: - NSSecureCoding
    
    /// Required for NSSecureCoding — prevents deserialization of unexpected classes.
    static var supportsSecureCoding: Bool { return true }
    
    // MARK: - Properties
    
    var title: String
    var photo: UIImage?
    var body: String
    var link: String
    var imagePath: String?
    
