    // URL validation delegated to URLValidator (with SSRF protection).
    
    // MARK: - Archiving Paths
    
    static var DocumentsDirectory = FileManager().urls(for: .documentDirectory, in: .userDomainMask).first!
    static var ArchiveURL = DocumentsDirectory.appendingPathComponent("stories")

    
    // MARK: - Types
    
    struct PropertyKey {
        static let titleKey = "title"
        static let photoKey = "photo"
        static let descriptionKey = "description"
        static let linkKey = "link"
        static let imagePathKey = "imagePath"
        static let sourceFeedNameKey = "sourceFeedName"
    }
    
    // MARK: - Initialization
    
    /// Creates a new story from RSS feed data.
