            self.imagePath = path
        } else {
            self.imagePath = nil
        }
        
        self.sourceFeedName = sourceFeedName
        
        super.init()
        
        if title.isEmpty || body.isEmpty || !Story.isSafeURL(link) {
            return nil
        }
    }
    
